mapper.select:
SELECT e.id, e.executor_code AS executorCode, e.executor_name AS executorName, e.description, e.protocol_id AS protocolId, p.protocol_name AS protocolName, e.status, e.create_user_id AS createUserId, e.create_user_name AS createUserName, e.create_time AS createTime, e.update_user_id AS updateUserId, e.update_user_name AS updateUserName, e.update_time AS updateTime, e.reserve, e.remark FROM agent_executor e LEFT JOIN agent_protocol p ON e.protocol_id = p.id
AND e.executor_code LIKE CONCAT('%', #{pageRequest.executorCode}, '%')
AND e.executor_name LIKE CONCAT('%', #{pageRequest.executorName}, '%')
AND e.protocol_id = #{pageRequest.protocolId}
AND e.status = #{pageRequest.status}
ORDER BY e.create_time DESC
